/* eslint-disable */

import defaultConfig from '../core/config/default-config.js';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const LH_ROOT = path.join(__dirname, '..');

async function run() {
  const perfAuditRefs = defaultConfig.categories.performance.auditRefs;
  const auditPaths = defaultConfig.audits;

  // Build a map of audit ID to its class
  const auditIdToMeta = new Map();

  for (const auditPath of auditPaths) {
    try {
      const fullPath = path.join(LH_ROOT, 'core/audits', `${auditPath}.js`);
      const { default: AuditClass } = await import(fullPath);
      if (AuditClass && AuditClass.meta) {
        auditIdToMeta.set(AuditClass.meta.id, AuditClass.meta);
      }
    } catch (e) {
      console.error(`Failed to load audit at ${auditPath}: ${e.message}`);
    }
  }

  const results = perfAuditRefs.map(ref => {
    const meta = auditIdToMeta.get(ref.id);
    return {
      group: ref.group,
      id: ref.id,
      name: meta ? (typeof meta.title === 'string' ? meta.title : meta.title.formattedDefault) : 'N/A',
      description: meta ? (typeof meta.description === 'string' ? meta.description : meta.description.formattedDefault) : 'N/A',
    };
  });

  console.log('| Group | ID | Name | Description |');
  console.log('| :--- | :--- | :--- | :--- |');
  for (const row of results) {
    const description = row.description.replace(/\n/g, ' ').replace(/\|/g, '\\|');
    console.log(`| ${row.group} | ${row.id} | ${row.name} | ${description} |`);
  }
}

run().catch(console.error);
